sys_script_include.script:
function HtmlRenderIcon(strIcon,nSize,bSpinning)
{
	strIcon = GetStringValue(strIcon);
	nSize = GetIntegerValue(nSize);
	bSpinning = GetBoolValue(bSpinning); 

	if (strIcon == '')
	{
		return '';
	}

	var strHtml = '';
	strHtml += '<link type="text/css" rel="stylesheet" href="/scripts/icon-fonts/font-awesome/css/font-awesome.css"></link>';

	var strClasses = 'fa fa-'+strIcon;
	if (bSpinning == true)
	{
		strClasses += ' fa-spin';
	}
	if (nSize > 5)
	{
		nSize = 5;
	}
	if (nSize > 1)
	{
		strClasses += ' fa-'+nSize+'x';
	}
	strClasses += ' fa-fw';

	strHtml += '<i class="'+strClasses+'"></i>';	
	return strHtml;
}
